const companyData = $('Prepare Company Data').item.json;
const companyName = companyData.companyName || '';
const domain = companyData.domain || '';
let content = '';
let contentSource = '';

// Try website scrape first
try {
  const scrapeData = $('Jina Website Scrape').item.json;
  const webContent = (scrapeData.data || {}).content || '';
  const hasWarning = !!(scrapeData.data || {}).warning;
  if (!hasWarning && typeof webContent === 'string' && webContent.trim().length > 200) {
    content = webContent;
    contentSource = 'website';
  }
} catch(e) {}

// Fall back to search
if (!content) {
  try {
    const searchData = $('Jina Web Search').item.json;
    const webContent = (searchData.data || {}).content || '';
    if (typeof webContent === 'string' && webContent.trim().length > 50) {
      content = webContent;
      contentSource = 'search';
    }
  } catch(e) {}
}

// Clean content
content = content.replace(/!\[.*?\]\(.*?\)/g, '');
content = content.replace(/https?:\/\/[^\s)]+\.(png|jpg|jpeg|gif|svg|webp|ico)[^\s)]*/gi, '');
content = content.replace(/cookie[s]?\s*(policy|notice|consent|banner|settings)[^\n]*/gi, '');

if (contentSource === 'search') {
  content = content.replace(/Report Ad[^\n]*/g, '');
  content = content.replace(/\[.*?\]\(https:\/\/duckduckgo\.com\/y\.js[^)]*\)/g, '');
  content = content.replace(/^.*duckduckgo\.com\/y\.js.*$/gm, '');
  content = content.replace(/^\d+\.\s+\S+\.\S+\s*$/gm, '');
  const match = content.match(/\n\d+\.\s/);
  if (match && match.index > 300) {
    content = content.substring(match.index);
  }
  content = content.replace(/\nMore results[\s\S]*/, '');
  content = content.replace(/Close menu[\s\S]*/, '');
  content = content.replace(/\[Only include results[^\]]*\]\([^)]*\)/g, '');
  content = content.replace(/\[Redo search[^\]]*\]\([^)]*\)/g, '');
  content = content.replace(/\[Block this site[^\]]*\]\([^)]*\)/g, '');
  content = content.replace(/Share feedback about this site/g, '');
  content = content.replace(/\[Search domain[^\]]*\]\([^)]*\)/g, '');
  content = content.replace(/\[\]\(https:\/\/duckduckgo\.com\/\?q=[^)]*\)/g, '');
}

content = content.replace(/\n{3,}/g, '\n\n').trim();

const maxChars = 6000;
if (content.length > maxChars) content = content.substring(0, maxChars) + '... [truncated]';

const prompt = `You are an expert at identifying the headquarters country of companies from web content.

COMPANY: ${companyName}
DOMAIN: ${domain || 'Not provided'}

WEB CONTENT:
${content || 'No content available'}

---

Based ONLY on the web content above, identify the headquarters country.

LOOK FOR (in order of reliability):
1. Physical address or registered office mentioned on the page
2. Phone number with international country code (e.g., +33 = France, +44 = UK, +32 = Belgium)
3. VAT/tax ID format (e.g., BE0xxx = Belgium, DE xxx = Germany, GB xxx = UK)
4. Company registration or legal entity type (GmbH = Germany/Austria/Switzerland, BV/NV = Netherlands/Belgium, Ltd/PLC = UK, SRL/SA = various, Inc/LLC = USA)
5. Explicit statement like "headquartered in [city], [country]" or "based in [country]"
6. Language and regional formatting clues (currency symbols, date formats)

RULES:
- Base your answer ONLY on the provided web content — do NOT use your own knowledge about company names or domains
- Do NOT confuse a company with another similarly named well-known company (e.g., "apollosuccess.io" is NOT "apollo.io", "wixsiteautomations.com" is NOT "wix.com")
- The evidence field MUST contain a direct quote from the web content, NOT your reasoning
- If the content is only error pages, login screens, or cookie banners with zero location clues: output Unknown

COUNTRY NAME RULES:
- Use full English country names
- NEVER use "England", "Scotland", "Wales", or "Northern Ireland" — always use "United Kingdom"
- NEVER use "Holland" — use "Netherlands"
- NEVER use "USA" or "US" — use "United States"
- NEVER use "UAE" — use "United Arab Emirates"

RESPONSE (JSON only, no markdown, no explanation):
{"country": "<full country name>", "evidence": "<exact quote from content>"}

If unknown:
{"country": "Unknown", "evidence": "No country indicators found in content"}`;
return { json: { companyId: companyData.companyId, companyName, domain, contentSource, contentLength: content.length, prompt } };

const geminiText = ($json?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const companyData = $('Prepare Company Data').item.json;
const contentSource = $('Prepare Gemini Input').item.json.contentSource || '';

let geminiCountry = '';
let geminiEvidence = '';

try {
  const cleaned = geminiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const country = parsed.country || '';
  geminiEvidence = parsed.evidence || '';
  if (country && country !== 'Unknown') {
    geminiCountry = country;
  }
} catch (e) {}

return {
  json: {
    companyId: companyData.companyId,
    companyName: companyData.companyName,
    domain: companyData.domain,
    geminiCountry,
    geminiEvidence,
    contentSource
  }
};

const d = $input.item.json;
const country = d.countryFromTLD || d.countryFromName || d.countryFromAmplemarket || d.geminiCountry || '';
let enrichmentSource = '';
if (d.countryFromTLD) enrichmentSource = 'Domain Code';
else if (d.countryFromName) enrichmentSource = 'Company Name';
else if (d.countryFromAmplemarket) enrichmentSource = 'Amplemarket';
else if (d.geminiCountry) enrichmentSource = d.contentSource === 'website' ? 'Website' : 'Web Search';
return { json: { companyId: d.companyId, companyName: d.companyName, domain: d.domain || '', country, enrichmentSource, resolved: true } };

const companyData = $('Prepare Company Data').item.json;
return {
  json: {
    companyId: companyData.companyId,
    companyName: companyData.companyName,
    country: 'Unknown',
    enrichmentSource: 'Unresolved',
    resolved: false
  }
};

const d = $('Snapshot Data').item.json;
return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    country: d.country,
    enrichmentSource: d.enrichmentSource,
    resolved: d.resolved
  }
};

// Use static data to accumulate results across batches from different IF branches
const staticData = $getWorkflowStaticData('node');
const execId = $execution.id;

// Reset if new execution
if (staticData._execId !== execId) {
  staticData._execId = execId;
  staticData._results = [];
  staticData._sent = false;
}

// Add current batch items
const currentItems = $input.all().map(i => i.json);
staticData._results.push(...currentItems);

const totalExpected = $('Split All Companies').all().length;

// Only send when all items collected and not already sent
if (staticData._results.length >= totalExpected && !staticData._sent) {
  staticData._sent = true;
  const allResults = [...staticData._results];
  const resolved = allResults.filter(i => i.resolved);
  const unknown = allResults.filter(i => !i.resolved);
  const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
  const hubspotBase = 'https://app.hubspot.com/contacts/142047914/company/';
  let msg = `*\ud83c\udf0d Country Enrichment \u2014 ${today}*\n*${allResults.length} companies processed*\n`;
  if (resolved.length > 0) {
    msg += `\n\u2705 *${resolved.length} enriched:*\n`;
    for (const c of resolved) {
      msg += `\u2022 *${c.companyName}* \u2192 ${c.country} _(${c.enrichmentSource})_ \u2014 <${hubspotBase}${c.companyId}|View>\n`;
    }
  }
  if (unknown.length > 0) {
    msg += `\n\ud83d\udea9 *${unknown.length} unknown:*\n`;
    for (const c of unknown) {
      msg += `\u2022 *${c.companyName}* \u2014 <${hubspotBase}${c.companyId}|View>\n`;
    }
  }
  return [{ json: { message: msg } }];
}

// Not all items yet — return empty (Slack won't trigger)
return [];

const companyData = $('Prepare Company Data').item.json;
let content = '';

// Try website scrape content (available when coming from Check Website Data TRUE path)
try {
  const scrapeData = $('Jina Website Scrape').item.json;
  const webContent = (scrapeData.data || {}).content || '';
  if (webContent) content += webContent + '\n';
} catch(e) {}

// Try search results content (available when coming from Jina Web Search path)
try {
  const searchData = $('Jina Web Search').item.json;
  const searchContent = (searchData.data || {}).content || '';
  if (searchContent) content += searchContent;
} catch(e) {}

const linkedinMatch = content.match(/https?:\/\/(?:www\.)?linkedin\.com\/company\/[a-zA-Z0-9_-]+/i);
const linkedinUrl = linkedinMatch ? linkedinMatch[0] : '';

return {
  json: {
    ...companyData,
    linkedinUrl
  }
};

const data = $json;
